import anthropic
import time
from dataclasses import dataclass, field
from typing import Literal

client = anthropic.Anthropic()


@dataclass
class RouteConfig:
    task_type: str
    priority: Literal["realtime", "batch"] = "realtime"
    max_tokens: int = 1024
    # Cached system prompt to prepend (large stable prefix)
    cached_system: str = ""


BATCH_QUEUE: list[dict] = []


def cached_call(
    config: RouteConfig,
    user_message: str,
    model: str,
) -> anthropic.types.Message:
    """Make a real-time call with prompt caching on the system prompt."""
    messages = [
        {
            "role": "user",
            "content": [
                {
                    "type": "text",
                    "text": user_message,
                }
            ],
        }
    ]

    # Build system with cache_control on stable prefix
    system_content = []
    if config.cached_system:
        system_content.append(
            {
                "type": "text",
                "text": config.cached_system,
                # Marks this block for caching: next request with same prefix
                # reads at ~0.1x input price instead of full price
                "cache_control": {"type": "ephemeral"},
            }
        )

    kwargs = dict(
        model=model,
        max_tokens=config.max_tokens,
        messages=messages,
    )
    if system_content:
        kwargs["system"] = system_content

    return client.messages.create(**kwargs)


def enqueue_batch(config: RouteConfig, user_message: str, model: str, custom_id: str):
    """Add request to the batch queue instead of sending immediately."""
    BATCH_QUEUE.append(
        {
            "custom_id": custom_id,
            "params": {
                "model": model,
                "max_tokens": config.max_tokens,
                "messages": [{"role": "user", "content": user_message}],
            },
        }
    )


def flush_batch() -> list[dict]:
    """Send all queued requests through the Batch API (50% discount)."""
    if not BATCH_QUEUE:
        return []

    batch = client.messages.batches.create(requests=list(BATCH_QUEUE))
    BATCH_QUEUE.clear()

    # Poll until complete (up to 24 hours in production; short timeout here)
    for _ in range(60):
        status = client.messages.batches.retrieve(batch.id)
        if status.processing_status == "ended":
            break
        time.sleep(5)

    results = []
    for result in client.messages.batches.results(batch.id):
        if result.result.type == "succeeded":
            msg = result.result.message
            results.append({
                "custom_id": result.custom_id,
                "text": msg.content[0].text,
                "input_tokens": msg.usage.input_tokens,
                "output_tokens": msg.usage.output_tokens,
            })
    return results


def route(config: RouteConfig, user_message: str, custom_id: str = "") -> dict | None:
    """Main routing entry point."""
    MODELS = {
        "simple":   "claude-haiku-4-5",
        "standard": "claude-sonnet-5",
        "complex":  "claude-opus-4-8",
    }
    input_est = (len(config.cached_system) + len(user_message)) // 4
    if config.task_type in ("classification", "extraction") and input_est < 800:
        tier = "simple"
    elif config.task_type in ("synthesis", "reasoning") or input_est > 8000:
        tier = "complex"
    else:
        tier = "standard"

    model = MODELS[tier]

    if config.priority == "batch":
        enqueue_batch(config, user_message, model, custom_id or user_message[:32])
        return None  # result retrieved later via flush_batch()

    response = cached_call(config, user_message, model)
    return {
        "text": response.content[0].text,
        "model": model,
        "tier": tier,
        "cache_read_tokens": getattr(response.usage, "cache_read_input_tokens", 0),
        "cache_write_tokens": getattr(response.usage, "cache_creation_input_tokens", 0),
    }


# --- Example ---
SYSTEM_PROMPT = "You are an expert document analyst. " + "Review guidelines: " * 200  # large stable prefix

config = RouteConfig(
    task_type="extraction",
    priority="realtime",
    max_tokens=256,
    cached_system=SYSTEM_PROMPT,
)

r = route(config, "Extract the company name from: 'Acme Corp reported Q3 revenue of $4.2B.'")
print(r)

import anthropic

client = anthropic.Anthropic()

messages = [
    {"role": "user", "content": "Summarize the following document: " + "x" * 5000}
]

# Count tokens WITHOUT making an inference call
token_count = client.messages.count_tokens(
    model="claude-haiku-4-5",
    messages=messages,
)

print(f"Input tokens: {token_count.input_tokens}")

# Route based on exact token count before committing to a model
if token_count.input_tokens < 2000:
    model = "claude-haiku-4-5"
elif token_count.input_tokens < 50_000:
    model = "claude-sonnet-5"
else:
    model = "claude-opus-4-8"  # longest context handling

print(f"Selected model: {model}")
